export async function getRandomWord(): Promise<string> {
  if (!process.env.API_KEY) {
    throw new Error('API_KEY is not configured.');
  }

  // Adding a timestamp + random seed to force non-cached, unique results
  const randomSeed = Date.now() + Math.floor(Math.random() * 1000000);

  const prompt = `Generate a single, interesting, sophisticated English vocabulary word (SAT/GRE level). 
  It must be random and unique each time. 
  Seed: ${randomSeed}.
  Do NOT use these words: Serendipity, Petrichor, Ephemeral, Mellifluous, Sycophant.
  Respond with only the word itself, no punctuation.`;

  try {
    const response = await getAiClient().models.generateContent({
      model: textModelName,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        temperature: 1.5, // Extremely high temperature for maximum variance
      },
    });
    return response.text.trim();
  } catch (error) {
    console.error('Error getting random word from Gemini:', error);
    const errorMessage =
