  background: none;
  border: none;
  padding: 0;
  font: inherit;
  color: inherit;
  cursor: pointer;
}
.interactive-word {
  color: var(--text-color);
  text-decoration: none;
  transition: color 0.2s ease-in-out;
}
.interactive-word:hover {
  color: var(--accent-color);
  text-decoration: underline;
}

.ascii-art {
  font-family: monospace;
  text-align: left;
  white-space: pre;
  color: var(--text-color-muted);
  margin: 2rem 0;
  line-height: 1.1;
  font-size: 0.8em;
}
.blinking-cursor {
  animation: blink 1s step-end infinite;
}

/* Search Bar Styles */
.search-container {
  display: flex;
  align-items: center;
  gap: 1rem;
  margin-bottom: 2rem;
  width: 100%;
}

.search-form {
  flex-grow: 1;
}

.search-input {
  width: 100%;
  padding: 0.5rem 0.2rem;
  font: inherit;
  color: inherit;
  border: none;
  border-bottom: 1px solid var(--border-color);
  background-color: var(--input-bg);
  box-sizing: border-box;
  outline: none;
  transition: border-color 0.2s;
}
.search-input:focus {
  border-color: var(--text-color);
}

.search-input:disabled {
  color: var(--text-color-secondary);
}

.search-input::placeholder {
  color: var(--text-color-muted);
  opacity: 1;
}

.theme-toggle-btn {
  background: none;
  border: none;
  padding: 0.5rem;
  color: var(--text-color);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  transition: background 0.2s;
  position: relative;
}
.theme-toggle-btn:hover {
  background: var(--button-bg);
}
.theme-toggle-btn.active-user {
  color: var(--accent-color);
}
.user-dot {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 6px;
  height: 6px;
  background-color: var(--success-color);
  border-radius: 50%;
  border: 1px solid var(--bg-color);
}

/* Autocomplete Dropdown */
.suggestions-dropdown {
  position: absolute;
  top: 100%;
  left: 0;
  width: 100%;
  background-color: var(--card-bg);
  border: 1px solid var(--border-color);
  border-top: none;
  border-radius: 0 0 4px 4px;
  list-style: none;
  padding: 0;
  margin: 0;
  box-shadow: 0 4px 6px var(--shadow-color);
  z-index: 100;
  max-height: 250px; 
  overflow-y: auto;
}

.suggestion-item {
  width: 100%;
  padding: 0.75rem 1rem;
  text-align: left;
  background: none;
  border: none;
  color: var(--text-color);
  cursor: pointer;
  border-bottom: 1px solid var(--border-color);
  font-size: 1rem;
}

.suggestion-item:hover {
  background-color: var(--highlight-color);
}
.suggestion-item:last-child {
  border-bottom: none;
}

/* Wiki Page Sections */
.wiki-content {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  padding-bottom: 3rem;
}

.wiki-intro {
  margin-bottom: 1rem;
}

.wiki-section {
  border-left: 2px solid var(--border-color);
  padding-left: 1.5rem;
  transition: border-color 0.2s;
}
.wiki-section:hover {
  border-left-color: var(--text-color-secondary);
}

.wiki-section-title {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--text-color-muted);
  margin-bottom: 0.5rem;
  font-weight: bold;
}

.wiki-section-body p {
  margin: 0;
  line-height: 1.6;
}

/* Nav Buttons */
.nav-controls {
  display: flex;
  gap: 0.2rem;
}

.nav-btn {
  padding: 0.4rem;
  color: var(--text-color);
  border-radius: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s;
}

.nav-btn:hover:not(:disabled) {
  background: var(--button-bg);
}

.nav-btn:disabled {
  color: var(--text-color-muted);
  cursor: default;
  opacity: 0.5;
}

/* Home View Styles */
.home-view {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding-top: 2rem;
    gap: 3rem;
    animation: fadeIn 0.5s ease-in-out;
}

.app-title-large {
    font-size: 1.5rem;
    letter-spacing: 0.3em;
    text-transform: uppercase;
    text-align: center;
    margin-bottom: 1rem;
}

.home-buttons {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    width: 100%;
    max-width: 300px;
}

.home-btn {
    padding: 1rem 2rem;
    border: 1px solid var(--border-color);
    border-radius: 30px;
    background-color: var(--card-bg);
    color: var(--text-color);
    font-size: 1rem;
    letter-spacing: 0.05em;
    transition: all 0.2s ease;
    text-transform: uppercase;
    box-shadow: 0 2px 5px var(--shadow-color);
}

.home-btn:hover {
    background-color: var(--button-hover);
    transform: translateY(-2px);
    box-shadow: 0 4px 8px var(--shadow-color);
}

.home-btn:active {
    transform: translateY(0);
}

/* AI FAB */
.ai-fab {
    position: fixed;
    bottom: 2rem;
    right: 2rem;
    width: 56px;
    height: 56px;
    border-radius: 50%;
    background-color: var(--fab-bg);
    color: var(--fab-text);
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 4px 10px var(--shadow-color);
    transition: transform 0.2s ease;
    z-index: 1000;
}

.ai-fab:hover {
    transform: scale(1.1);
}

.save-star-btn {
    font-size: 1.5rem;
    background: none;
    border: none;
    cursor: pointer;
    color: var(--text-color-muted);
    padding: 0.2rem;
    transition: transform 0.2s, color 0.2s;
    line-height: 1;
}
.save-star-btn:hover {
    transform: scale(1.1);
}
.save-star-btn.saved {
    color: var(--gold-color);
}

/* Saved Words Overlay */
.saved-list-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: var(--overlay-bg);
    z-index: 2000;
    display: flex;
    align-items: center;
    justify-content: center;
    backdrop-filter: blur(5px);
}

.saved-list-container {
    width: 90%;
    max-width: 500px;
    height: 80vh;
    background-color: var(--card-bg);
    border: 1px solid var(--border-color);
    border-radius: 8px;
    padding: 2rem;
    display: flex;
    flex-direction: column;
    box-shadow: 0 10px 25px var(--shadow-color);
    position: relative;
}

.saved-list-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1.5rem;
}

.saved-list-header h3 {
    text-transform: uppercase;
    letter-spacing: 0.1em;
    font-size: 1.1rem;
}

.close-button {
    color: var(--text-color-secondary);
    font-size: 0.9rem;
}
.close-button:hover {
    color: var(--text-color);
}

.backup-controls {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 1.5rem;
    flex-wrap: wrap; /* Allows wrapping on small screens */
}
.backup-btn {
    font-size: 0.8rem;
    padding: 0.3rem 0.6rem;
    border: 1px solid var(--border-color);
    border-radius: 4px;
    white-space: nowrap; /* Prevents text from breaking inside button */
}
.backup-btn:hover {
    background-color: var(--button-bg);
}

.sort-controls {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 1rem;
    font-size: 0.85rem;
    color: var(--text-color-secondary);
    overflow-x: auto;
    padding-bottom: 5px;
    flex-shrink: 0; /* Prevents being squashed */
}
.sort-btn {
    background: none;
    border: 1px solid transparent;
    cursor: pointer;
    color: var(--text-color-muted);
    padding: 2px 6px;
    border-radius: 4px;
    white-space: nowrap;
}
.sort-btn.active {
    color: var(--text-color);
    border-color: var(--border-color);
    font-weight: bold;
}

.saved-words-ul {
    list-style: none;
    padding: 0;
    margin: 0;
    overflow-y: auto;
    flex-grow: 1;
}

.saved-word-item {
    padding: 0.8rem 0;
    border-bottom: 1px solid var(--border-color);
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.word-button {
    text-align: left;
    font-size: 1.1rem;
    flex-grow: 1;
}
.word-button:hover {
    color: var(--accent-color);
}

.edit-mode-container {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
}
.edit-word-input {
    flex-grow: 1;
    font-size: 1.1rem;
    padding: 0.2rem;
    border: 1px solid var(--border-color);
    border-radius: 4px;
    background-color: var(--input-bg);
    color: var(--text-color);
}
.delete-btn-edit-mode {
    background-color: var(--error-color);
    color: #fff;
    border-radius: 4px;
    padding: 0.3rem 0.6rem;
    font-size: 0.8rem;
}

.word-actions-menu {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
    width: 100%;
}
.action-btn {
    padding: 0.4rem 0.8rem;
    font-size: 0.85rem;
    border-radius: 4px;
    border: 1px solid var(--border-color);
    background-color: var(--card-bg);
    color: var(--text-color);
    transition: background-color 0.2s;
}
.action-btn:hover {
    background-color: var(--button-bg);
}
.action-btn.primary {
    border-color: var(--text-color);
    font-weight: bold;
}
.action-btn.danger {
    color: var(--error-color);
    border-color: var(--error-color);
}
.action-btn.danger:hover {
    background-color: var(--error-color);
    color: white;
}

.mastery-indicator {
    display: flex;
    gap: 3px;
    margin-top: 4px;
}
.mastery-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background-color: #eee;
}

.header-undo-btn {
    font-size: 0.8rem;
    color: var(--text-color);
    text-decoration: underline;
}

.undo-toast {
    position: absolute;
    bottom: 1rem;
    left: 50%;
    transform: translateX(-50%);
    background-color: var(--text-color);
    color: var(--bg-color);
    padding: 0.8rem 1.5rem;
    border-radius: 30px;
    display: flex;
    align-items: center;
    gap: 1rem;
    box-shadow: 0 4px 12px var(--shadow-color);
    z-index: 10;
}
.undo-btn {
    font-weight: bold;
    color: var(--gold-color);
}

.delete-history-btn {
    color: var(--text-color-muted);
    font-size: 1rem;
    padding: 0.5rem;
    margin-left: 0.5rem;
}
.delete-history-btn:hover {
    color: var(--error-color);
}
.star-btn-list {
    color: var(--text-color-muted);
    font-size: 1.2rem;
    padding: 0.2rem;
}
.star-btn-list.active {
    color: var(--gold-color);
}

/* Chat Overlay */
.chat-overlay {
    position: fixed;
    bottom: 5rem;
    right: 2rem;
    width: 350px;
    height: 500px;
    background-color: var(--card-bg);
    border: 1px solid var(--border-color);
    border-radius: 12px;
    box-shadow: 0 5px 20px var(--shadow-color);
    z-index: 1500;
    display: flex;
    flex-direction: column;
}

.chat-container {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.chat-header {
    padding: 1rem;
    border-bottom: 1px solid var(--border-color);
    display: flex;
    justify-content: space-between;
    align-items: center;
    background-color: var(--header-bg);
    border-radius: 12px 12px 0 0;
}

.chat-messages {
    flex-grow: 1;
    overflow-y: auto;
    padding: 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.8rem;
}

.message {
    padding: 0.8rem;
    border-radius: 8px;
    font-size: 0.95rem;
    max-width: 85%;
}

.message.user {
    align-self: flex-end;
    background-color: var(--msg-user-bg);
    color: var(--msg-user-text);
}

.message.model {
    align-self: flex-start;
    background-color: var(--msg-model-bg);
    color: var(--msg-model-text);
    border: 1px solid var(--border-color);
}

.chat-input-area {
    padding: 1rem;
    border-top: 1px solid var(--border-color);
    display: flex;
    gap: 0.5rem;
}

.chat-input {
    flex-grow: 1;
    padding: 0.5rem;
    border: 1px solid var(--border-color);
    border-radius: 4px;
    background-color: var(--input-bg);
    color: var(--text-color);
}

.chat-send-btn {
    padding: 0.5rem 1rem;
    background-color: var(--text-color);
    color: var(--bg-color);
    border-radius: 4px;
}

/* Flashcard Styles */
.flashcard-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: var(--bg-color);
    z-index: 1000;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1rem;
    box-sizing: border-box;
}

.flashcard-container {
    width: 100%;
    max-width: 500px;
    height: 90vh;
    display: flex;
    flex-direction: column;
    position: relative;
}

.flashcard-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
}

.mode-toggle {
    display: flex;
    background-color: var(--button-bg);
    border-radius: 20px;
    padding: 2px;
}

.mode-toggle button {
    padding: 0.5rem 1rem;
    border-radius: 18px;
    font-size: 0.9rem;
    color: var(--text-color-secondary);
}

.mode-toggle button.active {
    background-color: var(--card-bg);
    color: var(--text-color);
    box-shadow: 0 1px 3px var(--shadow-color);
}

/* Simplified Card Flip Logic */
.card {
    flex-grow: 1;
    cursor: pointer;
    margin-bottom: 1rem;
    position: relative; /* Ensure context */
}

.card-inner {
    position: relative;
    width: 100%;
    height: 100%;
    /* No 3D transform */
    box-shadow: 0 4px 15px var(--shadow-color);
    border-radius: 16px;
    background-color: var(--card-bg);
    overflow: hidden; /* clean edges */
    border: 1px solid var(--border-color);
}

.card-front, .card-back {
    position: absolute;
    width: 100%;
    height: 100%;
    top: 0;
    left: 0;
    display: flex;
    flex-direction: column;
    padding: 2rem;
    box-sizing: border-box;
    overflow-y: auto;
    background-color: var(--card-bg);
    transition: opacity 0.3s ease, transform 0.3s ease;
}

.card-front {
    opacity: 1;
    pointer-events: auto;
    z-index: 2;
    align-items: center;
    justify-content: center;
}

.card-back {
    opacity: 0;
    pointer-events: none;
    z-index: 1;
    align-items: flex-start;
    justify-content: flex-start;
    text-align: left;
    transform: scale(0.95);
}

/* Flipped State */
.card.flipped .card-front {
    opacity: 0;
    pointer-events: none;
    transform: scale(0.95);
}

.card.flipped .card-back {
    opacity: 1;
    pointer-events: auto;
    z-index: 2;
    transform: scale(1);
}

.card-word {
    font-size: 2.5rem;
    font-weight: bold;
    text-align: center;
}
.card-word-small {
    font-size: 1.5rem;
    font-weight: bold;
    margin: 0;
}
.card-instruction {
    color: var(--text-color-muted);
    font-size: 0.9rem;
    margin-top: 1rem;
}

.card-header-back {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid var(--border-color);
    padding-bottom: 1rem;
    margin-bottom: 1rem;
}

.save-icon-btn {
    font-size: 1.5rem;
    color: var(--text-color-muted);
}
.save-icon-btn.saved {
    color: var(--gold-color);
}

/* Collapsible Sections in Flashcard */
.collapsible-section {
    border-bottom: 1px solid var(--border-color);
}
.section-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 0;
    cursor: pointer;
}
.section-header h4 {
    margin: 0;
    font-size: 0.9rem;
    text-transform: uppercase;
    color: var(--text-color-secondary);
}
.section-content {
    padding-bottom: 1rem;
    font-size: 1rem;
    line-height: 1.5;
}
.arrow {
    font-size: 0.8rem;
    color: var(--text-color-muted);
}
.refresh-icon {
    font-size: 1.2rem;
    font-weight: bold;
}

/* Controls */
.flashcard-controls {
    height: 80px;
    display: flex;
    justify-content: center;
    align-items: center;
}

.reveal-btn, .next-btn {
    width: 100%;
    padding: 1rem;
    background-color: var(--text-color);
    color: var(--bg-color);
    border-radius: 8px;
    font-size: 1.1rem;
    font-weight: bold;
    text-transform: uppercase;
    letter-spacing: 0.1em;
}

.srs-buttons.simple {
    display: flex;
    gap: 1rem;
    width: 100%;
}

.srs-btn {
    flex: 1;
    padding: 1rem;
    border-radius: 8px;
    font-weight: bold;
    color: white;
    font-size: 1.1rem;
}

.srs-btn.know {
    background-color: var(--success-color);
}
.srs-btn.dont-know {
    background-color: var(--error-color);
}

/* Auth Modal Styles */
.auth-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: var(--overlay-bg);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 2000;
    backdrop-filter: blur(5px);
}

.auth-container {
    background-color: var(--card-bg);
    padding: 2rem;
    border-radius: 8px;
    border: 1px solid var(--border-color);
    width: 90%;
    max-width: 400px;
    box-shadow: 0 10px 25px var(--shadow-color);
    position: relative;
}

.auth-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 2rem;
}

.auth-header h3 {
    font-size: 1.2rem;
    font-weight: bold;
    letter-spacing: 0.05em;
}

.auth-form {
    display: flex;
    flex-direction: column;
    gap: 1rem;
}

.auth-input {
    padding: 0.8rem;
    background-color: var(--input-bg);
    border: 1px solid var(--border-color);
    color: var(--text-color);
    border-radius: 4px;
    font-family: inherit;
}

.auth-input:focus {
    outline: none;
    border-color: var(--text-color);
}

.auth-btn {
    padding: 0.8rem;
    border-radius: 4px;
    font-weight: bold;
    text-transform: uppercase;
    font-size: 0.9rem;
    letter-spacing: 0.1em;
    transition: all 0.2s;
}

.auth-btn.primary {
    background-color: var(--text-color);
    color: var(--bg-color);
    border: 1px solid var(--text-color);
}

.auth-btn.primary:hover:not(:disabled) {
    background-color: transparent;
    color: var(--text-color);
}

.auth-btn.primary:disabled {
    opacity: 0.7;
    cursor: wait;
}

.auth-btn.logout {
    width: 100%;
    background-color: transparent;
    border: 1px solid var(--error-color);
    color: var(--error-color);
}
.auth-btn.logout:hover {
    background-color: var(--error-color);
    color: white;
}

.auth-footer {
    margin-top: 1.5rem;
    text-align: center;
    font-size: 0.9rem;
    color: var(--text-color-secondary);
}

.auth-link-btn {
    color: var(--text-color);
    text-decoration: underline;
    font-weight: bold;
}

.auth-message {
    padding: 0.75rem;
    border-radius: 4px;
    font-size: 0.9rem;
    text-align: center;
}
.auth-message.error {
    background-color: rgba(229, 57, 53, 0.1);
    color: var(--error-color);
    border: 1px solid var(--error-color);
}
.auth-message.success {
    background-color: rgba(67, 160, 71, 0.1);
    color: var(--success-color);
    border: 1px solid var(--success-color);
}

/* Google Login & Divider */
.auth-google-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1rem;
    width: 100%;
    padding: 0.7rem;
    background-color: var(--card-bg);
    border: 1px solid var(--border-color);
    color: var(--text-color);
    border-radius: 4px;
    font-family: inherit;
    font-size: 0.95rem;
    transition: background-color 0.2s;
    margin-bottom: 0;
}

.auth-google-btn:hover {
    background-color: var(--bg-color-secondary);
}

.auth-divider {
    display: flex;
    align-items: center;
    text-align: center;
    margin: 1.5rem 0;
    color: var(--text-color-muted);
    font-size: 0.8rem;
}

.auth-divider::before,
.auth-divider::after {
    content: '';
    flex: 1;
    border-bottom: 1px solid var(--border-color);
}

.auth-divider span {
    padding: 0 10px;
}

/* STORY MODE STYLES */
.story-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: var(--bg-color);
    z-index: 1000;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1rem;
    box-sizing: border-box;
}

.story-container {
    width: 100%;
    max-width: 600px;
    height: 90vh;
    display: flex;
    flex-direction: column;
    position: relative;
    background-color: var(--card-bg);
}

.story-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 2rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid var(--border-color);
}

.story-setup-content {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.story-instruction {
    color: var(--text-color-secondary);
    font-size: 1rem;
    text-align: center;
}

.input-wrapper {
    position: relative;
    width: 100%;
}

.story-input {
    width: 100%;
    height: 150px;
    padding: 1rem;
    padding-right: 3rem; /* Space for button */
    border: 1px solid var(--border-color);
    border-radius: 8px;
    background-color: var(--input-bg);
    color: var(--text-color);
    font-family: inherit;
    font-size: 1.1rem;
    resize: none;
    box-sizing: border-box;
}

.mix-btn {
    position: absolute;
    bottom: 1rem;
    right: 1rem;
    width: 30px;
    height: 30px;
    border-radius: 50%;
    background-color: var(--bg-color);
    border: 1px solid var(--border-color);
    color: var(--text-color);
    font-size: 1.2rem;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    box-shadow: 0 2px 5px var(--shadow-color);
}
.mix-btn:hover {
    transform: rotate(180deg);
    transition: transform 0.3s ease;
}

.proceed-btn {
    padding: 1rem;
    background-color: var(--text-color);
    color: var(--bg-color);
    border-radius: 30px;
    font-size: 1.1rem;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    font-weight: bold;
}
.proceed-btn:disabled {
    opacity: 0.5;
    cursor: default;
}

.story-content {
    flex-grow: 1;
    overflow-y: auto;
    padding: 0 1rem;
    margin-bottom: 2rem;
}

.story-text {
    font-size: 1.2rem;
    line-height: 1.8;
    white-space: pre-wrap;
    text-align: justify;
}

.story-word {
    cursor: pointer;
    border-bottom: 1px solid transparent;
    transition: border-color 0.2s;
    position: relative;
}
.story-word:hover {
    border-bottom-color: var(--text-color-muted);
}
.story-word.active {
    background-color: var(--highlight-color);
    border-radius: 3px;
    color: var(--text-color);
}

.story-controls {
    display: flex;
    justify-content: space-between;
    gap: 1rem;
    padding-top: 1rem;
    border-top: 1px solid var(--border-color);
}

.nav-btn-story {
    padding: 0.8rem 1.5rem;
    border: 1px solid var(--border-color);
    border-radius: 8px;
    font-size: 0.9rem;
    color: var(--text-color);
}
.nav-btn-story.primary {
    background-color: var(--text-color);
    color: var(--bg-color);
}
.nav-btn-story:disabled {
    opacity: 0.5;
}

/* Tooltip Styles */
.tooltip {
    position: fixed;
    background-color: var(--text-color);
    color: var(--bg-color);
    padding: 1rem;
    border-radius: 8px;
    box-shadow: 0 4px 15px rgba(0,0,0,0.3);
    z-index: 2000;
    width: 250px;
    font-size: 0.9rem;
    animation: fadeIn 0.2s ease;
}

.tooltip-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.8rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid rgba(128,128,128,0.3);
}

.tooltip-header strong {
    text-transform: capitalize;
    color: var(--gold-color);
    font-size: 1rem;
}

.tooltip-pos {
    font-weight: normal;
    color: var(--bg-color);
    opacity: 0.7;
    margin-left: 6px;
    font-size: 0.85em;
}

.wiki-icon-btn {
    background: none;
    border: none;
    color: var(--bg-color); /* Contrast against dark tooltip bg */
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background-color 0.2s;
}
.wiki-icon-btn:hover {
    background-color: rgba(255,255,255,0.2);
}

.tooltip p {
    margin: 0;
    line-height: 1.4;
}

.tooltip-arrow {
    position: absolute;
    bottom: -6px;
    left: 20px;
    width: 0; 
    height: 0; 
    border-left: 6px solid transparent;
    border-right: 6px solid transparent;
    border-top: 6px solid var(--text-color);
}

.story-loading {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: var(--text-color-muted);
}
.spinner {
    width: 30px;
    height: 30px;
    border: 3px solid var(--border-color);
    border-top-color: var(--text-color);
    border-radius: 50%;
    animation: spin 1s linear infinite;
    margin-bottom: 1rem;
}
@keyframes spin {
    to { transform: rotate(360deg); }
}
